import{_ as o,c as t,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"프라이버시: 민감 정보 보호 | opencode-supermemory","description":"opencode-supermemory 프라이버시 보호 메커니즘을 학습하세요. private 태그로 데이터 마스킹, API Key 안전 설정 방법을 익힙니다.","frontmatter":{"title":"프라이버시: 민감 정보 보호 | opencode-supermemory","sidebarTitle":"프라이버시 보호","subtitle":"프라이버시와 데이터 보안: 민감한 정보 보호 방법","description":"opencode-supermemory 프라이버시 보호 메커니즘을 학습하세요. private 태그로 데이터 마스킹, API Key 안전 설정 방법을 익힙니다.","tags":["프라이버시","보안","설정"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"ko/supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"ko/supermemoryai/opencode-supermemory/security/privacy/index.md"}'),s={name:"ko/supermemoryai/opencode-supermemory/security/privacy/index.md"};function i(n,e,d,c,l,p){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="프라이버시와-데이터-보안-민감한-정보-보호-방법" tabindex="-1">프라이버시와 데이터 보안: 민감한 정보 보호 방법 <a class="header-anchor" href="#프라이버시와-데이터-보안-민감한-정보-보호-방법" aria-label="Permalink to &quot;프라이버시와 데이터 보안: 민감한 정보 보호 방법&quot;">​</a></h1><h2 id="학습-완료-후-할-수-있는-것" tabindex="-1">학습 완료 후 할 수 있는 것 <a class="header-anchor" href="#학습-완료-후-할-수-있는-것" aria-label="Permalink to &quot;학습 완료 후 할 수 있는 것&quot;">​</a></h2><ul><li><strong>데이터가 어디로 가는지 이해</strong>: 어떤 데이터가 클라우드에 업로드되고, 어떤 데이터가 로컬에 남아있는지 명확히 이해.</li><li><strong>마스킹 기술 마스터</strong>: <code>&lt;private&gt;</code> 태그를 사용하여 민감한 정보(예: 비밀번호, 키)가 업로드되지 않도록 방지.</li><li><strong>키 안전 관리</strong>: 가장 안전한 방식으로 <code>SUPERMEMORY_API_KEY</code>를 설정.</li></ul><h2 id="핵심-아이디어" tabindex="-1">핵심 아이디어 <a class="header-anchor" href="#핵심-아이디어" aria-label="Permalink to &quot;핵심 아이디어&quot;">​</a></h2><p>opencode-supermemory를 사용할 때, 데이터 흐름을 이해하는 것이 매우 중요합니다:</p><ol><li><strong>클라우드 저장</strong>: 메모리(Memories)는 로컬 파일이 아닌 Supermemory의 클라우드 데이터베이스에 저장됩니다. 이는 메모리에 접근하려면 네트워크 연결이 필요함을 의미합니다.</li><li><strong>로컬 마스킹</strong>: 프라이버시 보호를 위해, 플러그인은 데이터를 클라우드로 전송하기 <strong>전</strong>에 로컬에서 마스킹 처리를 수행합니다.</li><li><strong>명시적 제어</strong>: 플러그인은 자동으로 모든 파일을 스캔하여 업로드하지 않습니다. Agent가 명시적으로 <code>add</code> 도구를 호출하거나 압축을 트리거할 때만 관련 콘텐츠가 처리됩니다.</li></ol><h3 id="마스킹-메커니즘" tabindex="-1">마스킹 메커니즘 <a class="header-anchor" href="#마스킹-메커니즘" aria-label="Permalink to &quot;마스킹 메커니즘&quot;">​</a></h3><p>플러그인은 <code>&lt;private&gt;</code> 태그를 인식하는 간단한 필터를 내장하고 있습니다.</p><ul><li><strong>입력</strong>: <code>여기 데이터베이스 비밀번호는 &lt;private&gt;123456&lt;/private&gt;</code></li><li><strong>처리</strong>: 플러그인이 태그를 감지하고, 그 내용을 <code>[REDACTED]</code>로 교체.</li><li><strong>업로드</strong>: <code>여기 데이터베이스 비밀번호는 [REDACTED]</code></li></ul><div class="info custom-block"><p class="custom-block-title">팁</p><p>이 처리 과정은 플러그인 내부 코드에서 발생하며, 데이터가 컴퓨터를 떠나기 전에 이미 완료됩니다.</p></div><h2 id="함께-따라하세요" tabindex="-1">함께 따라하세요 <a class="header-anchor" href="#함께-따라하세요" aria-label="Permalink to &quot;함께 따라하세요&quot;">​</a></h2><h3 id="_1단계-api-key-안전-설정" tabindex="-1">1단계: API Key 안전 설정 <a class="header-anchor" href="#_1단계-api-key-안전-설정" aria-label="Permalink to &quot;1단계: API Key 안전 설정&quot;">​</a></h3><p>API Key를 설정 파일에 직접 작성할 수 있지만, 실수로 유출되는 것을 방지하기 위해(예: 설정 파일을 타인과 공유), 우선순위 논리를 이해하는 것이 좋습니다.</p><p><strong>우선순위 규칙</strong>:</p><ol><li><strong>설정 파일</strong> (<code>~/.config/opencode/supermemory.jsonc</code>): 우선순위 가장 높음.</li><li><strong>환경 변수</strong> (<code>SUPERMEMORY_API_KEY</code>): 설정 파일에 설정되지 않은 경우 이 변수를 사용.</li></ol><p><strong>권장 방법</strong>: CI/CD 환경에서 유연하게 전환하거나 사용하려면 환경 변수를 사용하세요. 개인 개발자라면, 사용자 디렉토리의 JSONC 파일에 설정하는 것도 안전합니다(프로젝트 Git 저장소에 없으므로).</p><h3 id="_2단계-private-태그-사용" tabindex="-1">2단계: <code>&lt;private&gt;</code> 태그 사용 <a class="header-anchor" href="#_2단계-private-태그-사용" aria-label="Permalink to &quot;2단계: `&lt;private&gt;` 태그 사용&quot;">​</a></h3><p>자연어로 Agent에게 민감한 정보를 포함하는 콘텐츠를 기억하게 할 때, 민감한 부분을 <code>&lt;private&gt;</code> 태그로 감쌀 수 있습니다.</p><p><strong>작업 데모</strong>:</p><p>Agent에게 말하세요:</p><blockquote><p>기억해 주세요, 프로덕션 환경 데이터베이스 IP는 192.168.1.10이지만, root 비밀번호는 <code>&lt;private&gt;SuperSecretPwd!&lt;/private&gt;</code>이며, 비밀번호를 유출하지 마세요.</p></blockquote><p><strong>다음을 보아야 합니다</strong>: Agent는 <code>supermemory</code> 도구를 호출하여 메모리를 저장합니다. Agent의 응답에 비밀번호가 포함될 수 있지만(컨텍스트에 있으므로), <strong>Supermemory 클라우드에 실제로 저장된 메모리</strong>는 이미 마스킹되어 있습니다.</p><h3 id="_3단계-마스킹-결과-확인" tabindex="-1">3단계: 마스킹 결과 확인 <a class="header-anchor" href="#_3단계-마스킹-결과-확인" aria-label="Permalink to &quot;3단계: 마스킹 결과 확인&quot;">​</a></h3><p>검색을 통해 방금의 비밀번호가 실제로 저장되지 않았는지 확인할 수 있습니다.</p><p><strong>작업</strong>: Agent에게 방금의 메모리를 검색하도록 요청:</p><blockquote><p>프로덕션 데이터베이스의 비밀번호를 검색해 주세요.</p></blockquote><p><strong>예상 결과</strong>: Agent가 Supermemory에서 검색한 콘텐츠는 다음이어야 함: <code>프로덕션 환경 데이터베이스 IP는 192.168.1.10이지만, root 비밀번호는 [REDACTED]...</code></p><p>Agent가 &quot;비밀번호는 [REDACTED]&quot;라고 알려주면, 마스킹 메커니즘이 정상 작동함을 의미합니다.</p><h2 id="일반적인-오해" tabindex="-1">일반적인 오해 <a class="header-anchor" href="#일반적인-오해" aria-label="Permalink to &quot;일반적인 오해&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">오해 1: 모든 코드가 업로드됩니다</p><p><strong>사실</strong>: 플러그인은 코드베이스 전체를 자동으로 업로드하지 <strong>않습니다</strong>. <code>/supermemory-init</code>을 실행하여 초기화 스캔을 수행하거나, Agent가 명시적으로 &quot;이 코드 로직을 기억하기로&quot; 결정할 때만 특정 세그먼트를 업로드합니다.</p></div><div class="warning custom-block"><p class="custom-block-title">오해 2: .env 파일이 자동으로 로드됩니다</p><p><strong>사실</strong>: 플러그인은 프로세스 환경의 <code>SUPERMEMORY_API_KEY</code>를 읽습니다. 프로젝트 루트 디렉토리에 <code>.env</code> 파일을 넣어도, 플러그인은 사용하는 터미널 또는 OpenCode 메인 프로그램이 로드하지 않는 한 <strong>자동으로 읽지 않습니다</strong>.</p></div><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>소스 코드 위치 보려면 클릭</strong></summary><blockquote><p>업데이트: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>프라이버시 마스킹 로직</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>API Key 로드</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>플러그인 호출 마스킹</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>핵심 함수</strong>:</p><ul><li><code>stripPrivateContent(content)</code>: 정규 표현식 치환을 수행하여 <code>&lt;private&gt;</code> 내용을 <code>[REDACTED]</code>로 변환.</li><li><code>loadConfig()</code>: 로컬 설정 파일 로드, 환경 변수보다 우선순위 높음.</li></ul></details><h2 id="다음-수업-예고" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><blockquote><p>축하합니다! opencode-supermemory의 핵심 수업을 완료했습니다!</p><p>이제 다음을 할 수 있습니다:</p><ul><li><a href="/docs/opencodedocs/ko/supermemoryai/opencode-supermemory/advanced/configuration/">고급 설정</a>을 검토하여 더 많은 사용자 정의 옵션 이해.</li></ul></blockquote>',35)])])}const g=o(s,[["render",i]]);export{m as __pageData,g as default};
